import{c as e,Q as n,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"HavenBot — overview","description":"Your in-dashboard AI copilot for confidential RWA portfolio actions.","frontmatter":{"title":"HavenBot — overview","description":"Your in-dashboard AI copilot for confidential RWA portfolio actions."},"headers":[],"relativePath":"havenbot/overview.md","filePath":"havenbot/overview.md","lastUpdated":1778983454000}'),t={name:"havenbot/overview.md"};function i(r,a,l,p,c,d){return n(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="havenbot" tabindex="-1">HavenBot <a class="header-anchor" href="#havenbot" aria-label="Permalink to &quot;HavenBot&quot;">​</a></h1><p>HavenBot is MuHaven&#39;s <strong>in-dashboard agent</strong>. It lives at <code>muhaven.app/agent</code> and operates the same SDK and policy gate as every other surface, with a guided UX layered on top: streaming chat, per-action ConfirmModal, FHE-decrypted previews assembled in-browser.</p><p>It&#39;s the lowest-friction way to start using MuHaven agentically — no terminal, no install, no host config. Open the dashboard, sign in with your passkey, click <strong>Agent</strong>, and you&#39;re in.</p><h2 id="start-with-a-playbook" tabindex="-1">Start with a playbook <a class="header-anchor" href="#start-with-a-playbook" aria-label="Permalink to &quot;Start with a playbook&quot;">​</a></h2><p>The fastest way to get value out of HavenBot is to copy a phrase that already works. Pick the side that matches your role:</p><div class="mh-card-grid mh-card-grid--hero"><a class="mh-card mh-card--hero" href="/havenbot/investor-playbook"><h3>🪙 Investor playbook</h3><p><strong>Copy-paste phrases for buying, claiming, rebalancing, and setting your policy.</strong></p><p>&quot;Show my portfolio.&quot; · &quot;Buy 50 mhUSDC of <code>&lt;TOKEN&gt;</code>.&quot; · &quot;Claim all my pending yield.&quot; · &quot;Switch me to Confirm-per-action.&quot; · &quot;Pause my agent.&quot;</p><p><em>Read this if you hold encrypted RWA tokens and want to drive them by asking.</em></p></a><a class="mh-card mh-card--hero" href="/havenbot/issuer-playbook"><h3>🏛 Issuer playbook</h3><p><strong>Copy-paste phrases for distributing yield, managing KYC, activating new tokens, minting checkout links.</strong></p><p>&quot;Distribute $50,000 of yield to <code>RWA1</code> holders for May.&quot; · &quot;Add 0xabc…123 to <code>RWA1</code>&#39;s whitelist.&quot; · &quot;Set NAV and unpause <code>RWA1</code>.&quot; · &quot;Create a checkout for 500 mhUSDC of <code>RWA1</code>.&quot;</p><p><em>Read this if you create RWA tokens, schedule yield epochs, or run KYC.</em></p></a></div><p>Both pages are conversation-first: each row is <strong>say this → agent calls that → here&#39;s the cleartext preview you&#39;ll confirm</strong>. They&#39;re the quickest path from &quot;I have a passkey&quot; to &quot;I&#39;m running this portfolio by asking.&quot;</p><h2 id="what-havenbot-can-do" tabindex="-1">What HavenBot can do <a class="header-anchor" href="#what-havenbot-can-do" aria-label="Permalink to &quot;What HavenBot can do&quot;">​</a></h2><p><strong>Read (no signing):</strong></p><ul><li>Portfolio summary with <code>ebool</code> signal flags (<code>isOverexposed</code>, <code>isUnderYield</code>).</li><li>Quote at current NAV before purchase.</li><li>Unseal a specific encrypted handle (decrypts client-side via your permit).</li><li>Protection-coverage state for any RWA token.</li></ul><p><strong>Propose (signed via passkey or session key):</strong></p><ul><li>Buy / claim / rebalance.</li><li>Set tier (Advisory ↔ Confirm-per-action ↔ Policy-bound).</li><li>Pause the agent (kill-switch).</li><li>Encrypted governance vote.</li></ul><p><strong>Issuer-only:</strong></p><ul><li>Distribute yield to a token&#39;s holders.</li><li>Add / remove an investor from the KYC whitelist.</li><li>Set initial NAV and unpause a freshly-deployed token.</li><li>Query the issuer-side audit log.</li><li>Create a hosted-checkout link.</li></ul><p>A full table is on the <a href="/reference/tool-catalog">Tool catalog</a> page.</p><h2 id="how-havenbot-looks" tabindex="-1">How HavenBot looks <a class="header-anchor" href="#how-havenbot-looks" aria-label="Permalink to &quot;How HavenBot looks&quot;">​</a></h2><p>The HavenBot UI sits in your dashboard:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ MuHaven                                          [⚙ Settings]│</span></span>
<span class="line"><span>├─────────────────┬────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                 │  HavenBot                                  │</span></span>
<span class="line"><span>│  ▸ Portfolio    │  ─────────────────                         │</span></span>
<span class="line"><span>│  ▸ Deposit      │                                            │</span></span>
<span class="line"><span>│  ▸ Yields       │  You — 11:42                               │</span></span>
<span class="line"><span>│  ▸ Activity     │  Show my portfolio.                        │</span></span>
<span class="line"><span>│                 │                                            │</span></span>
<span class="line"><span>│  ▸ Agent ●      │  HavenBot — 11:42                          │</span></span>
<span class="line"><span>│                 │  You hold 3 RWA tokens. Status: balanced.  │</span></span>
<span class="line"><span>│  ─── Issuer ─── │  (encrypted-balance handle hidden)         │</span></span>
<span class="line"><span>│  ▸ Tokens       │                                            │</span></span>
<span class="line"><span>│  ▸ Distribute   │  You — 11:43                               │</span></span>
<span class="line"><span>│  ▸ Investors    │  Buy 50 mhUSDC of &lt;TOKEN&gt;.                 │</span></span>
<span class="line"><span>│  ▸ Compliance   │                                            │</span></span>
<span class="line"><span>│                 │  HavenBot — 11:43                          │</span></span>
<span class="line"><span>│                 │  ┌────────── ConfirmModal ──────────┐      │</span></span>
<span class="line"><span>│                 │  │ Buy 50.00 mhUSDC of &lt;TOKEN&gt;      │      │</span></span>
<span class="line"><span>│                 │  │ Estimated shares: ~49.85         │      │</span></span>
<span class="line"><span>│                 │  │ NAV: $1.003 · slippage 0.30%     │      │</span></span>
<span class="line"><span>│                 │  │ [Cancel]            [Confirm]    │      │</span></span>
<span class="line"><span>│                 │  └─────────────────────────────────┘       │</span></span>
<span class="line"><span>│                 │                                            │</span></span>
<span class="line"><span>└─────────────────┴────────────────────────────────────────────┘</span></span></code></pre></div><p>Three things to note:</p><ol><li><strong>Streaming responses</strong> — replies tokenize live so you can interrupt or follow up.</li><li><strong>ConfirmModal</strong> — every state-mutating action opens a cleartext-preview modal before signing. No silent execution, even in Confirm-per-action tier.</li><li><strong>In-line widgets</strong> — portfolio cards, quote widgets, and signal flags render in-place instead of as raw JSON.</li></ol><h2 id="the-three-components-under-the-hood" tabindex="-1">The three components under the hood <a class="header-anchor" href="#the-three-components-under-the-hood" aria-label="Permalink to &quot;The three components under the hood&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your message</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  HavenBot LLM    │  reads context (tier, recent audit, tool availability)</span></span>
<span class="line"><span>│  produces tool   │</span></span>
<span class="line"><span>│  intent JSON     │</span></span>
<span class="line"><span>└──────┬───────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  Policy gate     │  tier check (Advisory/Confirm/Policy-bound)</span></span>
<span class="line"><span>│  (deterministic) │  @zerodev/permissions validator scope</span></span>
<span class="line"><span>│                  │  RiskParams encrypted threshold check</span></span>
<span class="line"><span>└──────┬───────────┘</span></span>
<span class="line"><span>       │ approved</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  MuHaven SDK     │  MuHaven wallet + session-key sender writes the UserOp</span></span>
<span class="line"><span>│  call            │  ZeroDev bundler relays</span></span>
<span class="line"><span>└──────┬───────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  Audit log       │  WORM append, permit-grant events recorded</span></span>
<span class="line"><span>└──────────────────┘</span></span></code></pre></div><p>The <strong>LLM never holds keys</strong> and never directly invokes a wallet method. It produces structured tool-call intents; the policy gate is the only path to a signer.</p><p>A prompt-injection attempt that would have triggered an off-policy tool call is rejected by the gate before the intent reaches the signer. This is the <strong>CaMeL planner/action split</strong> — the planner LLM is kept out of the signing path entirely.</p><h2 id="onboarding-wizard" tabindex="-1">Onboarding wizard <a class="header-anchor" href="#onboarding-wizard" aria-label="Permalink to &quot;Onboarding wizard&quot;">​</a></h2><p>First-time visitors land on <code>/agent/onboarding</code> instead of <code>/agent</code> proper. The wizard is a four-step explainer:</p><ol><li>Welcome (sealed-glass-envelope copy).</li><li>Funding (faucet for testnet; on-ramp for production).</li><li>First buy (pick a token, set an amount, confirm).</li><li>Celebrate (set tier, link Telegram, install MCP).</li></ol><p>Returning users skip past steps they&#39;ve already completed — a <code>muhaven:onboarding:complete</code> localStorage flag plus a backend portfolio probe gates the wizard so it doesn&#39;t re-prompt you on repeat visits.</p><p>Read the full walkthrough at <a href="/havenbot/onboarding">Onboarding</a>.</p><h2 id="privacy-properties" tabindex="-1">Privacy properties <a class="header-anchor" href="#privacy-properties" aria-label="Permalink to &quot;Privacy properties&quot;">​</a></h2><ul><li>Your encrypted balances stay on-chain as ciphertext. HavenBot reads aggregates and <code>ebool</code> flags. Cleartext previews are assembled in your browser via <code>decryptForView(handle).withPermit().execute()</code> — the backend doesn&#39;t see them.</li><li>The LLM provider (Gemini today) sees your chat transcript and the tool-call envelopes. It does NOT see raw FHE handles.</li><li>The chat history is server-managed. You can clear it from <code>/agent → ⋯ menu → Clear chat</code>.</li><li>Every state-mutating tool emits an audit log row. Read tools intentionally do not log (privacy floor) — see <a href="/policy/audit-log">Audit log</a>.</li></ul><h2 id="when-to-use-havenbot" tabindex="-1">When to use HavenBot <a class="header-anchor" href="#when-to-use-havenbot" aria-label="Permalink to &quot;When to use HavenBot&quot;">​</a></h2><p>✅ You&#39;re new to MuHaven and want the guided UX. ✅ You like click-confirmable previews. ✅ You don&#39;t have or want a separate MCP host. ✅ You&#39;re an issuer and want the in-product audit copilot. ✅ You want the lowest-friction surface — open dashboard, ask, done.</p><p>❌ You want to bring your own LLM (use <a href="/mcp/overview">MCP</a>). ❌ You&#39;re on a phone and want one-tap actions (use <a href="/openclaw/telegram-bot">Telegram</a>). ❌ You&#39;re an issuer minting a one-off pay link for someone without a MuHaven account (use <a href="/checkout/overview">Hosted Checkout</a>).</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><div class="mh-card-grid"><a class="mh-card" href="/havenbot/onboarding"><h3>Onboarding</h3><p>From passkey to first encrypted buy.</p></a><a class="mh-card" href="/havenbot/conversations"><h3>Conversations &amp; confirmations</h3><p>How the chat, ConfirmModal, and signing flow actually work.</p></a><a class="mh-card" href="/havenbot/troubleshooting"><h3>Troubleshooting</h3><p>Symptom-first guide for the most common HavenBot hiccups.</p></a><a class="mh-card" href="/reference/tool-catalog"><h3>Tool catalog</h3><p>Every tool side-by-side across all four surfaces.</p></a></div>`,36)])])}const g=e(t,[["render",i]]);export{u as __pageData,g as default};
